module.exports = async (page, scenario) => {
  // Wait for all network requests to finish (images, fonts, CSS)
  await page.waitForNetworkIdle({ idleTime: 750, timeout: 15000 }).catch(() => {});

  // Wait for all fonts to finish loading
  await page.evaluate(() => document.fonts.ready);

  // Wait for all images to fully decode
  await page.evaluate(() =>
    Promise.all(
      [...document.images].map(
        (img) =>
          img.complete
            ? Promise.resolve()
            : new Promise((resolve) => {
                img.addEventListener('load', resolve);
                img.addEventListener('error', resolve);
              })
      )
    )
  );

  // Hide third-party widgets that change between runs
  await page.evaluate(() => {
    const selectors = [
      '#launcher',
      '.intercom-lightweight-app',
      '[id^="beacon-"]',
    ];
    selectors.forEach((sel) => {
      const el = document.querySelector(sel);
      if (el) el.style.display = 'none';
    });
  });
};

