module.exports = async (page, scenario) => {
  // Wait for network to settle, bail after 10s if still active
  await page.waitForNetworkIdle({ idleTime: 750, timeout: 10000 }).catch(() => {});

  // Wait for fonts, with a hard timeout fallback
  await Promise.race([
    page.evaluate(() => document.fonts.ready),
    new Promise((resolve) => setTimeout(resolve, 5000)),
  ]).catch(() => {});

  // Wait for images with a hard timeout fallback — avoids hanging on broken/slow images
  await Promise.race([
    page.evaluate(() =>
      Promise.all(
        [...document.images].map(
          (img) =>
            img.complete
              ? Promise.resolve()
              : new Promise((resolve) => {
                  img.addEventListener('load', resolve);
                  img.addEventListener('error', resolve);
                })
        )
      )
    ),
    new Promise((resolve) => setTimeout(resolve, 8000)),
  ]).catch(() => {});

  // Hide third-party widgets that change between runs
  await page.evaluate(() => {
    const selectors = [
      '#launcher',
      '.intercom-lightweight-app',
      '[id^="beacon-"]',
